from hypothesis import given
from hypothesis import strategies as st
from my.print import print_error


def describe_function_print_error():
    """la fonction print_error()"""

    @given(message=st.text())
    def it_prints_on_error_out(message: str, capsys):
        """affiche un message sur la sortie d'erreur"""
        print_error(message)

        captured = capsys.readouterr()

        assert captured.err == f"erreur: {message}.\n"
